	DELETED_DATE,
	IS_DELETED
) as SELECT "ID", "PARK_CODE", "MAC_ADDRESS", "CREATED_AT", "UPDATED_AT", "FILE_MODIFICATION_TIME", "END_DATE", DECODE(END_DATE, NULL, FALSE, TRUE) 
FROM "HAVEN_RAW"."DIG_ARRIVALS_ETLEAP"."ANPR_DEVICE";

create or replace view haven_base.dig_arrivals.ANPR_DEVICE                                                                                            
( ID, PARK_CODE, MAC_ADDRESS, CREATED_AT, UPDATED_AT, NAME, DIRECTION, ENABLED, DELETED_DATE, is_deleted )                                            
AS SELECT ID, PARK_CODE, MAC_ADDRESS, CREATED_AT, UPDATED_AT, NAME, DIRECTION, ENABLED, END_DATE, DECODE(END_DATE, NULL, FALSE, TRUE)  
FROM HAVEN_RAW.DIG_ARRIVALS_ETLEAP.ANPR_DEVICE;                                                                                                       
                                                                                                                                       
