create or replace view PURCHASE(
	ID,
	SHORTCODE,
	PAYMENTID,
	ISREEDEMED,
	ISREFUNDED,
	CREATEDAT,
	UPDATEDAT,
	ARRIVALDATE,
	PARKCODE,
	LEADGUESTNAME,
	REFUNDEDAT,
	ADULT,
	CHILD,
	CURRENCY,
	GROSSPRICE,
	NETPRICE,
	VATRATE,
	DEPARTUREDATE,
