 as SELECT ID, SHORTCODE, PAYMENTID, ISREEDEMED, ISREFUNDED, CREATEDAT, UPDATEDAT, ARRIVALDATE, PARKCODE, LEADGUESTNAME, REFUNDEDAT, ADULT, CHILD, CURRENCY, GROSSPRICE, NETPRICE, VATRATE, DEPARTUREDATE, "TYPE", EMAIL, PARKNAME, REFERENCEID, INFANT
